module reg_8bit (CLK, RST, EN, D, Q);
input CLK, RST, EN;
input [7:0] D;
output reg [7:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
    if (RST) begin
        Q <= 8'b00000000;
    end else if (EN) begin
        Q <= D;
    end
end

endmodule
